SELECT supplier_id, COUNT(component_id) AS component_count
FROM component_supplier_component
GROUP BY supplier_id;

SELECT component_name, description
FROM components
WHERE unit_price > (
  SELECT AVG(unit_price)
  FROM components
);

SELECT circuit_boards.board_id, circuit_boards.board_name, designers.designer_name
FROM circuit_boards
JOIN designers ON circuit_boards.designer_id = designers.designer_id;

SELECT AVG(c.lead_time) AS average_lead_time
FROM components c
INNER JOIN component_supplier_component csc ON c.component_id = csc.component_id;

SELECT circuit_boards.board_name, manufacturers.manufacturer_name
FROM circuit_boards
JOIN manufacturers ON circuit_boards.manufacturer_id = manufacturers.manufacturer_id;

SELECT AVG(experience) as average_experience
FROM designers
WHERE designer_id IN (
    SELECT designer_id
    FROM collaborations
);
